const pptxgen = require("pptxgenjs");
const pres = new pptxgen();

pres.layout = "LAYOUT_16x9";
pres.author = "CMG Data Team";
pres.title = "Average COGS Calculation - Old vs New Logic";

// Color palette - Ocean Gradient theme
const C = {
  navy: "1E2761",
  deepBlue: "065A82",
  teal: "1C7293",
  ice: "CADCFC",
  white: "FFFFFF",
  offWhite: "F4F7FB",
  dark: "1A1A2E",
  gray: "64748B",
  lightGray: "E2E8F0",
  accent: "00A896",
  red: "E74C3C",
  green: "27AE60",
  orange: "F39C12",
};

const mkShadow = () => ({ type: "outer", blur: 6, offset: 2, angle: 135, color: "000000", opacity: 0.12 });

// ============================================================
// SLIDE 1: Title Slide
// ============================================================
let s1 = pres.addSlide();
s1.background = { color: C.navy };

// Accent bar top
s1.addShape(pres.shapes.RECTANGLE, { x: 0, y: 0, w: 10, h: 0.06, fill: { color: C.accent } });

// Title block
s1.addText("Average COGS Calculation", {
  x: 0.8, y: 1.2, w: 8.4, h: 1.2,
  fontSize: 40, fontFace: "Georgia", color: C.white, bold: true, margin: 0,
});
s1.addText("Old vs New Requirement Logic", {
  x: 0.8, y: 2.3, w: 8.4, h: 0.8,
  fontSize: 26, fontFace: "Calibri", color: C.ice, margin: 0,
});
s1.addText("CMG Stock Aging FRS  |  Functional Requirement Change", {
  x: 0.8, y: 3.4, w: 8.4, h: 0.5,
  fontSize: 14, fontFace: "Calibri", color: C.gray, margin: 0,
});

// Bottom bar
s1.addShape(pres.shapes.RECTANGLE, { x: 0, y: 5.1, w: 10, h: 0.525, fill: { color: C.deepBlue } });
s1.addText("Central Marketing Group  |  Data Platform", {
  x: 0.8, y: 5.1, w: 8.4, h: 0.525,
  fontSize: 11, fontFace: "Calibri", color: C.ice, valign: "middle", margin: 0,
});

// ============================================================
// SLIDE 2: Agenda
// ============================================================
let s2 = pres.addSlide();
s2.background = { color: C.offWhite };

s2.addText("Agenda", {
  x: 0.8, y: 0.4, w: 8.4, h: 0.7,
  fontSize: 32, fontFace: "Georgia", color: C.navy, bold: true, margin: 0,
});
s2.addShape(pres.shapes.RECTANGLE, { x: 0.8, y: 1.1, w: 1.2, h: 0.04, fill: { color: C.accent } });

const agendaItems = [
  { num: "01", title: "Current FRS Logic (Old)", desc: "12-month lookback with span-based denominator" },
  { num: "02", title: "New Requirement Logic", desc: "Historical lookback with instant 12-month denominator" },
  { num: "03", title: "Side-by-Side Comparison", desc: "Same SKU scenarios under both calculation methods" },
  { num: "04", title: "Impact on Seasonal SKUs", desc: "How the change affects seasonal and existing articles" },
];

agendaItems.forEach((item, i) => {
  const yPos = 1.5 + i * 0.95;
  // Number circle
  s2.addShape(pres.shapes.OVAL, { x: 0.8, y: yPos, w: 0.55, h: 0.55, fill: { color: C.navy } });
  s2.addText(item.num, { x: 0.8, y: yPos, w: 0.55, h: 0.55, fontSize: 16, fontFace: "Georgia", color: C.white, align: "center", valign: "middle", margin: 0 });
  s2.addText(item.title, { x: 1.6, y: yPos - 0.02, w: 7, h: 0.32, fontSize: 18, fontFace: "Calibri", color: C.navy, bold: true, margin: 0 });
  s2.addText(item.desc, { x: 1.6, y: yPos + 0.3, w: 7, h: 0.25, fontSize: 13, fontFace: "Calibri", color: C.gray, margin: 0 });
});

// ============================================================
// SLIDE 3: Old Logic - Overview
// ============================================================
let s3 = pres.addSlide();
s3.background = { color: C.offWhite };

// Section tag
s3.addShape(pres.shapes.RECTANGLE, { x: 0.8, y: 0.35, w: 1.8, h: 0.35, fill: { color: C.navy } });
s3.addText("CURRENT FRS", { x: 0.8, y: 0.35, w: 1.8, h: 0.35, fontSize: 11, fontFace: "Calibri", color: C.white, align: "center", valign: "middle", bold: true, margin: 0 });

s3.addText("Old Logic: 12-Month Lookback Window", {
  x: 0.8, y: 0.85, w: 8.4, h: 0.6,
  fontSize: 28, fontFace: "Georgia", color: C.navy, bold: true, margin: 0,
});

// Formula box
s3.addShape(pres.shapes.RECTANGLE, { x: 0.8, y: 1.65, w: 8.4, h: 0.7, fill: { color: C.navy }, shadow: mkShadow() });
s3.addText("Average COGS  =  Sum of COGS across N months  /  N months", {
  x: 0.8, y: 1.65, w: 8.4, h: 0.7,
  fontSize: 18, fontFace: "Consolas", color: C.ice, align: "center", valign: "middle", margin: 0,
});

// Two cards
// Card 1: Window
s3.addShape(pres.shapes.RECTANGLE, { x: 0.8, y: 2.6, w: 4.0, h: 2.5, fill: { color: C.white }, shadow: mkShadow() });
s3.addShape(pres.shapes.RECTANGLE, { x: 0.8, y: 2.6, w: 4.0, h: 0.05, fill: { color: C.deepBlue } });
s3.addText("Lookback Window", { x: 1.0, y: 2.75, w: 3.6, h: 0.35, fontSize: 16, fontFace: "Calibri", color: C.navy, bold: true, margin: 0 });
s3.addText([
  { text: "Only looks at the past 12 months from the report date", options: { bullet: true, breakLine: true, fontSize: 13, color: C.dark } },
  { text: "", options: { breakLine: true, fontSize: 6 } },
  { text: "Example: Oct 2025 report looks at Nov 2024 - Oct 2025", options: { bullet: true, breakLine: true, fontSize: 13, color: C.dark } },
  { text: "", options: { breakLine: true, fontSize: 6 } },
  { text: "No visibility into data before the 12-month window", options: { bullet: true, fontSize: 13, color: C.dark } },
], { x: 1.0, y: 3.2, w: 3.6, h: 1.8, fontFace: "Calibri", valign: "top", margin: 0 });

// Card 2: Denominator
s3.addShape(pres.shapes.RECTANGLE, { x: 5.2, y: 2.6, w: 4.0, h: 2.5, fill: { color: C.white }, shadow: mkShadow() });
s3.addShape(pres.shapes.RECTANGLE, { x: 5.2, y: 2.6, w: 4.0, h: 0.05, fill: { color: C.orange } });
s3.addText("Denominator (N)", { x: 5.4, y: 2.75, w: 3.6, h: 0.35, fontSize: 16, fontFace: "Calibri", color: C.navy, bold: true, margin: 0 });
s3.addText([
  { text: "N = Span from first transaction within the 12-month window to current month", options: { bullet: true, breakLine: true, fontSize: 13, color: C.dark } },
  { text: "", options: { breakLine: true, fontSize: 6 } },
  { text: "If first data at Month 5 within window, N = 8 (not 12)", options: { bullet: true, breakLine: true, fontSize: 13, color: C.dark } },
  { text: "", options: { breakLine: true, fontSize: 6 } },
  { text: "Does NOT distinguish new vs old SKUs", options: { bullet: true, fontSize: 13, color: C.red, bold: true } },
], { x: 5.4, y: 3.2, w: 3.6, h: 1.8, fontFace: "Calibri", valign: "top", margin: 0 });

// ============================================================
// SLIDE 4: Old Logic - Example Table
// ============================================================
let s4 = pres.addSlide();
s4.background = { color: C.offWhite };

s4.addShape(pres.shapes.RECTANGLE, { x: 0.8, y: 0.35, w: 1.8, h: 0.35, fill: { color: C.navy } });
s4.addText("CURRENT FRS", { x: 0.8, y: 0.35, w: 1.8, h: 0.35, fontSize: 11, fontFace: "Calibri", color: C.white, align: "center", valign: "middle", bold: true, margin: 0 });

s4.addText("Old Logic: Example Scenarios", {
  x: 0.8, y: 0.85, w: 8.4, h: 0.5,
  fontSize: 26, fontFace: "Georgia", color: C.navy, bold: true, margin: 0,
});

const hdrOpts = { fill: { color: C.navy }, color: C.white, bold: true, fontSize: 9, fontFace: "Calibri", align: "center", valign: "middle" };
