from pptx import Presentation
from pptx.util import Inches, Pt, Emu
from pptx.enum.shapes import MSO_SHAPE_TYPE
from pptx.dml.color import RGBColor
from PIL import Image, ImageDraw, ImageFont
import os

prs = Presentation('/home/user/Stock_FRS/COGS_Old_vs_New_Logic.pptx')

# Scale: EMU to pixels at 150 DPI
# 1 inch = 914400 EMU, at 150 DPI = 150 pixels
# So 1 EMU = 150/914400 pixels
DPI = 150
SCALE = DPI / 914400.0

slide_w = int(prs.slide_width * SCALE)
slide_h = int(prs.slide_height * SCALE)
print(f"Image size: {slide_w}x{slide_h}")

def emu_to_px(emu):
    return int(emu * SCALE)

def get_rgb(color_obj):
    """Try to extract RGB from a color object."""
    try:
        if color_obj and color_obj.rgb:
            r = color_obj.rgb[0] if isinstance(color_obj.rgb[0], int) else int(color_obj.rgb[0:2], 16)
            # RGBColor is a string-like "RRGGBB"
            rgb_str = str(color_obj.rgb)
            return (int(rgb_str[0:2], 16), int(rgb_str[2:4], 16), int(rgb_str[4:6], 16))
    except:
        pass
    return None

def get_fill_color(shape):
    """Try to get fill color of a shape."""
    try:
        fill = shape.fill
        if fill.type is not None:
            fc = fill.fore_color
            if fc and fc.rgb:
                rgb_str = str(fc.rgb)
                return (int(rgb_str[0:2], 16), int(rgb_str[2:4], 16), int(rgb_str[4:6], 16))
    except:
        pass
    return None

for slide_idx, slide in enumerate(prs.slides):
    img = Image.new('RGB', (slide_w, slide_h), (255, 255, 255))
    draw = ImageDraw.Draw(img)

    for shape in slide.shapes:
        x = emu_to_px(shape.left)
        y = emu_to_px(shape.top)
        w = emu_to_px(shape.width)
        h = emu_to_px(shape.height)

        # Draw shape fill
        fill_color = get_fill_color(shape)
        if fill_color:
            draw.rectangle([x, y, x+w, y+h], fill=fill_color)

        # Draw shape outline
        try:
            line = shape.line
            if line and line.fill and line.fill.type is not None:
                lc = get_rgb(line.color)
                if lc:
                    draw.rectangle([x, y, x+w, y+h], outline=lc)
        except:
            pass

        # Draw table
        if shape.has_table:
            table = shape.table
            num_rows = len(table.rows)
            num_cols = len(table.columns)

            # Calculate column widths and row heights
            col_widths = [emu_to_px(table.columns[i].width) for i in range(num_cols)]
            row_heights = [emu_to_px(table.rows[i].height) for i in range(num_rows)]

            cy = y
            for ri, row in enumerate(table.rows):
                cx = x
                for ci, cell in enumerate(row.cells):
                    cw = col_widths[ci] if ci < len(col_widths) else w // num_cols
                    ch = row_heights[ri] if ri < len(row_heights) else h // num_rows

                    # Cell fill
                    try:
                        cf = cell.fill
                        if cf.type is not None:
                            fc = cf.fore_color
                            if fc and fc.rgb:
                                rgb_str = str(fc.rgb)
                                cc = (int(rgb_str[0:2], 16), int(rgb_str[2:4], 16), int(rgb_str[4:6], 16))
                                draw.rectangle([cx, cy, cx+cw, cy+ch], fill=cc)
                    except:
                        pass

                    # Cell border
                    draw.rectangle([cx, cy, cx+cw, cy+ch], outline=(200, 200, 200))

                    # Cell text
                    text = cell.text.strip()
                    if text:
                        font_size = 10
                        try:
                            for p in cell.text_frame.paragraphs:
                                for run in p.runs:
                                    if run.font.size:
                                        font_size = max(8, emu_to_px(run.font.size))
                                        break
                        except:
                            pass
                        try:
                            font = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf", font_size)
                        except:
                            font = ImageFont.load_default()

                        # Get text color
                        tc = (0, 0, 0)
                        try:
                            for p in cell.text_frame.paragraphs:
                                for run in p.runs:
                                    c = get_rgb(run.font.color)
                                    if c:
                                        tc = c
                                        break
                        except:
                            pass

                        draw.text((cx+3, cy+2), text[:20], fill=tc, font=font)

                    cx += cw
                cy += ch

        # Draw text
        if shape.has_text_frame:
            for p in shape.text_frame.paragraphs:
                text = p.text.strip()
                if not text:
                    continue
                font_size = 12
                tc = (0, 0, 0)
                for run in p.runs:
                    if run.font.size:
                        font_size = max(8, emu_to_px(run.font.size))
                    c = get_rgb(run.font.color)
                    if c:
                        tc = c

                try:
                    font = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf", font_size)
                except:
                    font = ImageFont.load_default()

                draw.text((x+3, y+2), text[:100], fill=tc, font=font)
                y += font_size + 4

    img.save(f'/tmp/cogs-slide-{slide_idx+1}.png')
    print(f"Saved slide {slide_idx+1}")

print("Done rendering all slides")
PYEOF

