s8.addText("Real-World Example", { x: 0.8, y: 4.05, w: 8.5, h: 0.3, fontSize: 15, fontFace: "Calibri", color: C.navy, bold: true, margin: 0 });
s8.addText([
  { text: "SKU \"Dyson V15\" has been sold since 2020, but only has COGS in Jul-Sep 2025 (seasonal promotion).", options: { fontSize: 12, color: C.dark, breakLine: true } },
  { text: "Old Logic: ", options: { bold: true, fontSize: 12, color: C.red } },
  { text: "First data at M7 in window, span = 6. Avg COGS = Total / 6 (inflated average)", options: { fontSize: 12, color: C.dark, breakLine: true } },
  { text: "New Logic: ", options: { bold: true, fontSize: 12, color: C.green } },
  { text: "Historical data found (2020). N = 12 instantly. Avg COGS = Total / 12 (true annual rate)", options: { fontSize: 12, color: C.dark } },
], { x: 0.8, y: 4.35, w: 8.5, h: 0.9, fontFace: "Calibri", valign: "top", margin: 0 });

// ============================================================
