s9.background = { color: C.navy };

s9.addShape(pres.shapes.RECTANGLE, { x: 0, y: 0, w: 10, h: 0.06, fill: { color: C.accent } });

s9.addText("Summary of Changes", {
  x: 0.8, y: 0.5, w: 8.4, h: 0.7,
  fontSize: 32, fontFace: "Georgia", color: C.white, bold: true, margin: 0,
});

// Key changes
const summaryItems = [
  { title: "Historical Lookback", desc: "System now checks all data from 2018 onwards to determine if a SKU is new or existing" },
  { title: "Instant N = 12 for Existing SKUs", desc: "Any SKU with historical data before the 12-month window automatically gets denominator = 12" },
  { title: "Accurate Seasonal Treatment", desc: "Seasonal SKUs are no longer treated as new articles, giving a true annual average" },
  { title: "New SKU Fallback Preserved", desc: "Truly new SKUs (no history) still use count of months with actual values" },
];

summaryItems.forEach((item, i) => {
  const yPos = 1.5 + i * 0.9;
  s9.addShape(pres.shapes.RECTANGLE, { x: 0.8, y: yPos, w: 8.4, h: 0.75, fill: { color: C.deepBlue } });
  s9.addText(item.title, { x: 1.1, y: yPos + 0.05, w: 7.8, h: 0.3, fontSize: 16, fontFace: "Calibri", color: C.accent, bold: true, margin: 0 });
  s9.addText(item.desc, { x: 1.1, y: yPos + 0.35, w: 7.8, h: 0.35, fontSize: 12, fontFace: "Calibri", color: C.ice, margin: 0 });
});

// Bottom
s9.addShape(pres.shapes.RECTANGLE, { x: 0, y: 5.1, w: 10, h: 0.525, fill: { color: C.deepBlue } });
s9.addText("CMG Stock Aging FRS  |  Average COGS Calculation Change", {
  x: 0.8, y: 5.1, w: 8.4, h: 0.525,
  fontSize: 11, fontFace: "Calibri", color: C.ice, valign: "middle", margin: 0,
});

// Write file
pres.writeFile({ fileName: "/home/user/Stock_FRS/COGS_Old_vs_New_Logic.pptx" })
  .then(() => console.log("Presentation created successfully!"))
  .catch(err => console.error("Error:", err));

