s5.background = { color: C.offWhite };

s5.addShape(pres.shapes.RECTANGLE, { x: 0.8, y: 0.35, w: 2.2, h: 0.35, fill: { color: C.accent } });
s5.addText("NEW REQUIREMENT", { x: 0.8, y: 0.35, w: 2.2, h: 0.35, fontSize: 11, fontFace: "Calibri", color: C.white, align: "center", valign: "middle", bold: true, margin: 0 });

