const pptxgen = require("pptxgenjs");
const pres = new pptxgen();

// Template: 13.33" x 7.5" (LAYOUT_WIDE) - matching CMG GCP Project Setup template
pres.layout = "LAYOUT_WIDE";
pres.author = "Deloitte Consulting";
pres.title = "Average COGS Calculation - Old vs New Logic";

const W = 13.33; // slide width
const H = 7.5;   // slide height

// Colors from template theme
const C = {
  black: "000000",
  white: "FFFFFF",
  darkBlue: "002776",
  red: "FF0000",       // accent1 - used for separator lines
  blue: "00A1DE",      // accent2
  darkGray: "313131",  // accent3
  green: "3C8A2E",     // accent4 - Deloitte green
  medGray: "575757",   // accent5
  lightGray: "8C8C8C", // accent6
  bgGray: "F2F2F2",
  lineGray: "D0D0CE",
  amber: "ED8B00",
};

// Template layout constants
const LEFT_MARGIN = 0.53;  // ~479424 EMU
const CONTENT_W = 12.2;    // ~11160000 EMU
const SECTION_Y = 0.36;
const TITLE_Y = 0.75;
const LINE_Y = 1.3;
const BODY_Y = 1.5;
const FOOTER_Y = 7.06;

// Helper: Add content slide chrome (header line, footer, confidential, page number)
function addSlideChrome(slide, sectionText, titleText, pageNum) {
  // Section tag (small caps style)
  slide.addText(sectionText, {
    x: LEFT_MARGIN, y: SECTION_Y, w: CONTENT_W, h: 0.2,
    fontSize: 9, fontFace: "Calibri", color: C.medGray, charSpacing: 1.5, margin: 0,
  });

  // Title
  slide.addText(titleText, {
    x: LEFT_MARGIN, y: TITLE_Y, w: CONTENT_W, h: 0.45,
    fontSize: 22, fontFace: "Calibri", color: C.black, bold: true, margin: 0,
  });

  // Red separator line (accent1 from template)
  slide.addShape(pres.shapes.LINE, {
    x: LEFT_MARGIN, y: LINE_Y, w: CONTENT_W, h: 0,
    line: { color: C.red, width: 3 },
  });

  // Footer left - document name
  slide.addText("CMG Unified Data Platform - Average COGS Calculation Old vs New", {
    x: 5.5, y: FOOTER_Y, w: 5.5, h: 0.25,
    fontSize: 7, fontFace: "Calibri", color: C.lightGray, align: "right", margin: 0,
  });

  // Footer right - page number + copyright
  slide.addText(`${pageNum} | Copyright \u00A9 2025 Deloitte T&T (Thailand) Co., Ltd.`, {
    x: LEFT_MARGIN, y: FOOTER_Y, w: 5, h: 0.25,
    fontSize: 7, fontFace: "Calibri", color: C.lightGray, align: "left", margin: 0,
  });

  // Confidential label top-right
  slide.addText("Confidential", {
    x: 11.7, y: 0.1, w: 1.0, h: 0.2,
    fontSize: 8, fontFace: "Calibri", color: C.lightGray, align: "right", margin: 0,
  });
}

// ============================================================
// SLIDE 1: Title Slide (matches template Layout 1 - with background image style)
// ============================================================
let s1 = pres.addSlide();
s1.background = { color: C.white };

// Title area background box (semi-transparent white overlay area like template)
s1.addShape(pres.shapes.RECTANGLE, {
  x: 0, y: 3.2, w: W, h: 4.3,
  fill: { color: C.white, transparency: 10 },
});

// Section tag (small caps)
s1.addText("AVERAGE COGS CALCULATION", {
  x: 1.0, y: 3.5, w: 6.5, h: 0.25,
  fontSize: 12, fontFace: "Calibri", color: C.black, charSpacing: 1.5, margin: 0,
});

// Green separator line
s1.addShape(pres.shapes.LINE, {
  x: 1.0, y: 3.85, w: 6.5, h: 0,
  line: { color: C.green, width: 3 },
});

// Main title
s1.addText("Old vs New Requirement Logic", {
  x: 1.0, y: 3.8, w: 8.0, h: 1.0,
  fontSize: 44, fontFace: "Calibri", color: C.black, bold: true, margin: 0,
});

// Subtitle
s1.addText("Unified Data Platform", {
  x: 1.0, y: 4.8, w: 6.5, h: 0.4,
  fontSize: 18, fontFace: "Calibri", color: C.black, bold: true, margin: 0,
});

// Date
s1.addText("CMG Stock Aging FRS  |  Functional Requirement Change", {
  x: 1.0, y: 5.6, w: 6.5, h: 0.3,
  fontSize: 18, fontFace: "Calibri", color: C.black, bold: true, margin: 0,
});

// Confidential
s1.addText("Confidential", {
  x: 11.7, y: 0.1, w: 1.0, h: 0.2,
  fontSize: 8, fontFace: "Calibri", color: C.lightGray, align: "right", margin: 0,
});

// ============================================================
// SLIDE 2: Agenda
// ============================================================
let s2 = pres.addSlide();
s2.background = { color: C.white };
addSlideChrome(s2, "AVERAGE COGS CALCULATION", "Agenda", 2);

const agendaItems = [
  { num: "01", title: "Current FRS Logic (Old)", desc: "12-month lookback with span-based denominator" },
  { num: "02", title: "New Requirement Logic", desc: "Historical lookback with instant 12-month denominator" },
  { num: "03", title: "Side-by-Side Comparison", desc: "Same SKU scenarios under both calculation methods" },
  { num: "04", title: "Impact on Seasonal SKUs", desc: "How the change affects seasonal and existing articles" },
];

agendaItems.forEach((item, i) => {
  const yPos = BODY_Y + 0.3 + i * 1.15;
  // Number box
  s2.addShape(pres.shapes.RECTANGLE, {
    x: LEFT_MARGIN, y: yPos, w: 0.6, h: 0.6,
    fill: { color: C.darkBlue },
  });
  s2.addText(item.num, {
    x: LEFT_MARGIN, y: yPos, w: 0.6, h: 0.6,
    fontSize: 18, fontFace: "Calibri", color: C.white, align: "center", valign: "middle", bold: true, margin: 0,
  });
  s2.addText(item.title, {
    x: 1.4, y: yPos, w: 10, h: 0.32,
    fontSize: 18, fontFace: "Calibri", color: C.black, bold: true, margin: 0,
  });
  s2.addText(item.desc, {
    x: 1.4, y: yPos + 0.32, w: 10, h: 0.28,
    fontSize: 13, fontFace: "Calibri", color: C.medGray, margin: 0,
  });
  // Subtle bottom border
  if (i < agendaItems.length - 1) {
    s2.addShape(pres.shapes.LINE, {
      x: LEFT_MARGIN, y: yPos + 0.9, w: 11.5, h: 0,
      line: { color: C.lineGray, width: 0.5 },
    });
  }
});

// ============================================================
// SLIDE 3: Old Logic - Overview
// ============================================================
let s3 = pres.addSlide();
s3.background = { color: C.white };
addSlideChrome(s3, "CURRENT FRS", "Old Logic: 12-Month Lookback Window", 3);

// Formula box
s3.addShape(pres.shapes.RECTANGLE, {
  x: LEFT_MARGIN, y: BODY_Y + 0.2, w: CONTENT_W, h: 0.65,
  fill: { color: C.darkBlue },
});
s3.addText("Average COGS  =  Sum of COGS across N months  /  N months", {
  x: LEFT_MARGIN, y: BODY_Y + 0.2, w: CONTENT_W, h: 0.65,
  fontSize: 18, fontFace: "Consolas", color: C.white, align: "center", valign: "middle", margin: 0,
});

// Two cards side by side
const cardY = BODY_Y + 1.1;
const cardH = 3.5;
const cardW = 5.8;

// Card 1: Lookback Window
s3.addShape(pres.shapes.RECTANGLE, {
  x: LEFT_MARGIN, y: cardY, w: cardW, h: cardH,
  fill: { color: C.bgGray },
});
s3.addShape(pres.shapes.RECTANGLE, {
  x: LEFT_MARGIN, y: cardY, w: cardW, h: 0.05,
  fill: { color: C.darkBlue },
});
s3.addText("Lookback Window", {
  x: LEFT_MARGIN + 0.3, y: cardY + 0.2, w: cardW - 0.6, h: 0.35,
  fontSize: 16, fontFace: "Calibri", color: C.black, bold: true, margin: 0,
});
s3.addText([
  { text: "Only looks at the past 12 months from the report date", options: { bullet: true, breakLine: true, fontSize: 13, color: C.darkGray } },
  { text: "", options: { breakLine: true, fontSize: 8 } },
  { text: "Example: Oct 2025 report looks at Nov 2024 - Oct 2025", options: { bullet: true, breakLine: true, fontSize: 13, color: C.darkGray } },
  { text: "", options: { breakLine: true, fontSize: 8 } },
  { text: "No visibility into data before the 12-month window", options: { bullet: true, fontSize: 13, color: C.darkGray } },
], { x: LEFT_MARGIN + 0.3, y: cardY + 0.65, w: cardW - 0.6, h: 2.5, fontFace: "Calibri", valign: "top", margin: 0 });

// Card 2: Denominator
s3.addShape(pres.shapes.RECTANGLE, {
  x: LEFT_MARGIN + cardW + 0.6, y: cardY, w: cardW, h: cardH,
  fill: { color: C.bgGray },
});
s3.addShape(pres.shapes.RECTANGLE, {
  x: LEFT_MARGIN + cardW + 0.6, y: cardY, w: cardW, h: 0.05,
  fill: { color: C.amber },
});
s3.addText("Denominator (N)", {
  x: LEFT_MARGIN + cardW + 0.9, y: cardY + 0.2, w: cardW - 0.6, h: 0.35,
  fontSize: 16, fontFace: "Calibri", color: C.black, bold: true, margin: 0,
});
s3.addText([
  { text: "N = Span from 1st transaction in window to current month", options: { bullet: true, breakLine: true, fontSize: 13, color: C.darkGray } },
  { text: "", options: { breakLine: true, fontSize: 8 } },
  { text: "First data at Month 5 within window, N = 8 (not 12)", options: { bullet: true, breakLine: true, fontSize: 13, color: C.darkGray } },
  { text: "", options: { breakLine: true, fontSize: 8 } },
  { text: "Does NOT distinguish new vs old SKUs", options: { bullet: true, fontSize: 13, color: C.red, bold: true } },
], { x: LEFT_MARGIN + cardW + 0.9, y: cardY + 0.65, w: cardW - 0.6, h: 2.5, fontFace: "Calibri", valign: "top", margin: 0 });

// ============================================================
// SLIDE 4: Old Logic - Example Table
// ============================================================
let s4 = pres.addSlide();
s4.background = { color: C.white };
addSlideChrome(s4, "CURRENT FRS", "Old Logic: Example Scenarios", 4);

const hdrOpts = { fill: { color: C.darkBlue }, color: C.white, bold: true, fontSize: 9, fontFace: "Calibri", align: "center", valign: "middle" };
const cellOpts = { fontSize: 9, fontFace: "Calibri", align: "center", valign: "middle", color: C.darkGray };
const emptyCell = { text: "-", options: { ...cellOpts, color: C.lineGray } };
const resultOpts = { fontSize: 9, fontFace: "Calibri", align: "center", valign: "middle", color: C.black, bold: true };

const oldTableData = [
  [
    { text: "SKU", options: hdrOpts },
    { text: "M1", options: hdrOpts }, { text: "M2", options: hdrOpts }, { text: "M3", options: hdrOpts },
    { text: "M4", options: hdrOpts }, { text: "M5", options: hdrOpts }, { text: "M6", options: hdrOpts },
    { text: "M7", options: hdrOpts }, { text: "M8", options: hdrOpts }, { text: "M9", options: hdrOpts },
    { text: "M10", options: hdrOpts }, { text: "M11", options: hdrOpts }, { text: "M12", options: hdrOpts },
    { text: "# Months\n(Span)", options: { ...hdrOpts, fill: { color: C.amber } } },
    { text: "Total", options: hdrOpts },
    { text: "Avg COGS", options: { ...hdrOpts, fill: { color: C.green } } },
  ],
  [
    { text: "SKU A\n(Existing)", options: { ...cellOpts, bold: true } },
