    { text: "100", options: cellOpts }, { text: "110", options: cellOpts }, { text: "120", options: cellOpts },
    { text: "12", options: { ...resultOpts, color: C.amber } },
    { text: "780", options: resultOpts },
    { text: "65.00", options: { ...resultOpts, color: C.green } },
  ],
  [
    { text: "SKU B\n(Seasonal)", options: { ...cellOpts, bold: true } },
    emptyCell, emptyCell, emptyCell, emptyCell, emptyCell, emptyCell,
    { text: "80", options: cellOpts }, { text: "90", options: cellOpts }, { text: "85", options: cellOpts },
    emptyCell, emptyCell, emptyCell,
    { text: "6", options: { ...resultOpts, color: C.red } },
    { text: "255", options: resultOpts },
    { text: "42.50", options: { ...resultOpts, color: C.red } },
  ],
