s4.addTable(oldTableData, {
  x: LEFT_MARGIN, y: BODY_Y + 0.2, w: CONTENT_W,
  colW: [1.1, 0.65, 0.65, 0.65, 0.65, 0.65, 0.65, 0.65, 0.65, 0.65, 0.65, 0.65, 0.65, 1.05, 0.85, 1.0],
