const pptxgen = require("pptxgenjs");
const pres = new pptxgen();

pres.layout = "LAYOUT_WIDE";
pres.author = "Deloitte Consulting";
pres.title = "Average COGS Calculation - Old vs New Logic";

const W = 13.33;
const H = 7.5;

const C = {
  black: "000000",
  white: "FFFFFF",
  darkBlue: "002776",
  red: "FF0000",
  blue: "00A1DE",
  darkGray: "313131",
  green: "3C8A2E",
  medGray: "575757",
  lightGray: "8C8C8C",
  bgGray: "F2F2F2",
  lineGray: "D0D0CE",
  amber: "ED8B00",
};

const LEFT = 0.53;
