const TITLE_Y = 0.75;
const LINE_Y = 1.3;
const BODY_Y = 1.5;
const FOOTER_Y = 7.06;

function addChrome(slide, section, title, page) {
  slide.addText(section, {
    x: LEFT, y: SECTION_Y, w: CW, h: 0.2,
    fontSize: 9, fontFace: "Calibri", color: C.medGray, charSpacing: 1.5, margin: 0,
