    x: 11.7, y: 0.1, w: 1.0, h: 0.2,
    fontSize: 8, fontFace: "Calibri", color: C.lightGray, align: "right", margin: 0,
  });
}

// ============================================================
// SLIDE 1: Title
// ============================================================
let s1 = pres.addSlide();
s1.background = { color: C.white };

