    s2.addShape(pres.shapes.LINE, { x: LEFT, y: y + 0.95, w: 11.5, h: 0, line: { color: C.lineGray, width: 0.5 } });
  }
});

// ============================================================
// SLIDE 3: Old Logic - Overview
// ============================================================
let s3 = pres.addSlide();
s3.background = { color: C.white };
addChrome(s3, "CURRENT FRS", "Old Logic: 12-Month Lookback Window", 3);

// Formula box
