s3.addText("Lookback Window", {
  x: LEFT + 0.3, y: cardY + 0.15, w: cardW - 0.6, h: 0.35,
  fontSize: 16, fontFace: "Calibri", color: C.black, bold: true, margin: 0,
});
s3.addText([
  { text: "Only looks at the past 12 months from report date", options: { bullet: true, breakLine: true, fontSize: 13, color: C.darkGray } },
