  { text: "", options: { breakLine: true, fontSize: 10 } },
  { text: "No visibility into data before May 2024", options: { bullet: true, fontSize: 13, color: C.darkGray } },
], { x: LEFT + 0.3, y: cardY + 0.6, w: cardW - 0.6, h: 2.8, fontFace: "Calibri", valign: "top", margin: 0, paraSpaceAfter: 6 });

// Card 2: Denominator
s3.addShape(pres.shapes.RECTANGLE, { x: LEFT + cardW + 0.6, y: cardY, w: cardW, h: cardH, fill: { color: C.bgGray } });
s3.addShape(pres.shapes.RECTANGLE, { x: LEFT + cardW + 0.6, y: cardY, w: cardW, h: 0.05, fill: { color: C.amber } });
