  x: LEFT + cardW + 0.9, y: cardY + 0.15, w: cardW - 0.6, h: 0.35,
  fontSize: 16, fontFace: "Calibri", color: C.black, bold: true, margin: 0,
});
s3.addText([
  { text: "N = Span from 1st transaction to current month", options: { bullet: true, breakLine: true, fontSize: 13, color: C.darkGray } },
  { text: "", options: { breakLine: true, fontSize: 10 } },
  { text: "First data at Aug 2024, report at Apr 2025", options: { bullet: true, breakLine: true, fontSize: 13, color: C.darkGray } },
  { text: "  \u2192 N = 9 (not 12)", options: { breakLine: true, fontSize: 13, color: C.amber, bold: true } },
  { text: "", options: { breakLine: true, fontSize: 10 } },
  { text: "Does NOT distinguish new vs old SKUs", options: { bullet: true, fontSize: 13, color: C.red, bold: true } },
], { x: LEFT + cardW + 0.9, y: cardY + 0.6, w: cardW - 0.6, h: 2.8, fontFace: "Calibri", valign: "top", margin: 0, paraSpaceAfter: 6 });

// ============================================================
// SLIDE 4: Old Logic - Real Data Table
// ============================================================
let s4 = pres.addSlide();
s4.background = { color: C.white };
addChrome(s4, "CURRENT FRS", "Old Logic: Article 11711000001 (Crocs)", 4);

// Context line
s4.addText("Report Month: Apr 2025  |  12-Month Window: May 2024 \u2013 Apr 2025  |  Brand: Crocs", {
  x: LEFT, y: BODY_Y + 0.05, w: CW, h: 0.3,
  fontSize: 11, fontFace: "Calibri", color: C.medGray, margin: 0,
});

const hdr = { fill: { color: C.darkBlue }, color: C.white, bold: true, fontSize: 8, fontFace: "Calibri", align: "center", valign: "middle" };
const cell = { fontSize: 9, fontFace: "Calibri", align: "center", valign: "middle", color: C.darkGray };
const dash = { text: "-", options: { fontSize: 9, fontFace: "Calibri", align: "center", valign: "middle", color: C.lineGray } };
const res = { fontSize: 9, fontFace: "Calibri", align: "center", valign: "middle", color: C.black, bold: true };

// Month headers: May'24 through Apr'25
const months = ["May'24","Jun'24","Jul'24","Aug'24","Sep'24","Oct'24","Nov'24","Dec'24","Jan'25","Feb'25","Mar'25","Apr'25"];

const oldData = [
  // Header
  [
