    { text: "749", options: cell },
    { text: "204", options: cell },
    { text: "477", options: cell },
    { text: "1,226", options: cell },
    { text: "545", options: cell },
    { text: "273", options: cell },
    dash,
    { text: "136", options: cell },
    { text: "68", options: cell },
