  { text: "4.  ", options: { bold: true, fontSize: 12, color: C.darkBlue } },
  { text: "Sum of COGS = 3,679.02", options: { fontSize: 12, color: C.darkGray, breakLine: true } },
  { text: "", options: { breakLine: true, fontSize: 6 } },
  { text: "5.  ", options: { bold: true, fontSize: 12, color: C.darkBlue } },
  { text: "Average COGS = 3,679.02 / 9 = ", options: { fontSize: 12, color: C.darkGray } },
  { text: "408.78", options: { fontSize: 14, color: C.red, bold: true } },
], { x: LEFT + 0.3, y: calcY + 0.5, w: 11, h: 2.0, fontFace: "Calibri", valign: "top", margin: 0 });

// Problem callout
const probY = BODY_Y + 4.35;
s4.addShape(pres.shapes.RECTANGLE, { x: LEFT, y: probY, w: CW, h: 0.8, fill: { color: "FFF3E0" } });
