    ],
  },
  numbering: {
    config: [
      { reference: "bullets", levels: [{ level: 0, format: LevelFormat.BULLET, text: "\u2022", alignment: AlignmentType.LEFT, style: { paragraph: { indent: { left: 720, hanging: 360 } } } }] },
      { reference: "numbers", levels: [{ level: 0, format: LevelFormat.DECIMAL, text: "%1.", alignment: AlignmentType.LEFT, style: { paragraph: { indent: { left: 720, hanging: 360 } } } }] },
    ],
  },
  sections: [{
    properties: {
      page: {
        size: { width: 12240, height: 15840 },
        margin: { top: 1440, right: 1440, bottom: 1440, left: 1440 },
      },
    },
    headers: {
      default: new Header({
        children: [
          new Paragraph({
            border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: RED, space: 4 } },
            children: [
              new TextRun({ text: "CMG Unified Data Platform  |  Stock Aging Report  |  Change Request", font: "Calibri", size: 16, color: GRAY }),
            ],
          }),
        ],
      }),
    },
    footers: {
      default: new Footer({
        children: [
          new Paragraph({
            border: { top: { style: BorderStyle.SINGLE, size: 4, color: LINE_GRAY, space: 4 } },
            children: [
              new TextRun({ text: "Confidential  |  Deloitte Consulting  |  Page ", font: "Calibri", size: 16, color: GRAY }),
              new TextRun({ children: [PageNumber.CURRENT], font: "Calibri", size: 16, color: GRAY }),
            ],
          }),
        ],
      }),
    },
    children: [
      // ========== EMAIL HEADER ==========
      p([
        { text: "Subject: ", bold: true, color: GRAY },
        { text: "[CR] Stock Aging Report \u2014 Change in Average COGS Calculation Logic", bold: true, color: DK_BLUE },
      ], { spaceAfter: 200, size: 24 }),

      separator(),

      p("Dear All,", { spaceAfter: 200 }),
      p("I would like to inform you of a Change Request (CR) regarding the Average COGS calculation in the Stock Aging report under the Unified Data Platform project.", { spaceAfter: 200 }),

      // ========== SECTION 1: Current Logic ==========
      separator(),
      sectionHeader("What was built (Current Logic \u2014 as per FRS)"),
      p("", { spaceAfter: 80 }),

      p("The Stock Aging report currently calculates the Average COGS by looking at the last 12 months from the report date. The system finds the first month that has a COGS value within that window and counts the number of months from there to the current month. This count is used as the denominator (N) to calculate the average.", { spaceAfter: 160 }),

      p("For example, if the report date is April 2025, and the first COGS appears in August 2024, then N = 9 months.", { spaceAfter: 120 }),

      calloutBox("Formula (Old Logic)", [
        { text: "Average COGS = Total COGS / N", bold: true, color: DK_BLUE },
        { text: "    where N = span from first transaction to current month", color: GRAY, break: 1 },
      ], DK_BLUE, "E8EAF6"),

      p("", { spaceAfter: 80 }),
      p([
        { text: "This logic was implemented ", size: 22 },
        { text: "exactly as specified in the signed-off FRS document.", bold: true, size: 22 },
      ], { spaceAfter: 200 }),

      // ========== SECTION 2: New Logic ==========
      separator(),
      sectionHeader("What is being requested (New Logic)"),
      p("", { spaceAfter: 80 }),

      p("The client has requested a change to how we determine the denominator (N):", { spaceAfter: 120 }),

      p([
        { text: "Before calculating, the system will now look back to the ", size: 22 },
        { text: "start of all available data (from 2018 onwards)", bold: true, color: DK_BLUE, size: 22 },
      ], { bullet: true, spaceAfter: 80 }),

      p([
        { text: "If the SKU has ", size: 22 },
        { text: "any sales history before the 12-month window", bold: true, size: 22 },
        { text: ", it is treated as an existing article, and ", size: 22 },
        { text: "N is set to 12 immediately", bold: true, color: GREEN, size: 22 },
      ], { bullet: true, spaceAfter: 80 }),

      p([
        { text: "If the SKU has ", size: 22 },
        { text: "no history at all", bold: true, size: 22 },
        { text: " (truly a new article created within the past 12 months), N will equal the ", size: 22 },
        { text: "number of months that actually have COGS values", bold: true, color: AMBER, size: 22 },
      ], { bullet: true, spaceAfter: 120 }),

      p("The purpose of this change is to give a more accurate average for seasonal or existing articles that may not have COGS in every month but have been sold in previous years.", { spaceAfter: 200 }),

      // ========== SECTION 3: Why It Matters ==========
      separator(),
      sectionHeader("Why does this matter?"),
      p("", { spaceAfter: 80 }),

      p([
        { text: "Using real data as an example (" },
        { text: "Article 11711000001 \u2014 Crocs brand", bold: true, color: DK_BLUE },
        { text: ", report month April 2025):" },
      ], { spaceAfter: 160 }),

      // Monthly COGS Table
      p("Monthly COGS within the 12-Month Window (May 2024 \u2013 Apr 2025)", { bold: true, size: 20, color: DK_BLUE, spaceAfter: 80 }),

      new Table({
        width: { size: 9360, type: WidthType.DXA },
        columnWidths: [1560, 780, 780, 780, 780, 780, 780, 780, 780, 780, 780],
        rows: [
          new TableRow({
