              headerCell("Total", GREEN),
            ],
          }),
          new TableRow({
            children: [
              dataCell("COGS", { bold: true, align: AlignmentType.LEFT, width: 1560, fill: LT_GRAY }),
              dataCell("749", { width: 780 }),
              dataCell("204", { width: 780 }),
              dataCell("477", { width: 780 }),
              dataCell("1,226", { width: 780 }),
              dataCell("545", { width: 780 }),
              dataCell("273", { width: 780 }),
              dataCell("-", { width: 780, color: LINE_GRAY }),
              dataCell("136", { width: 780 }),
              dataCell("68", { width: 780 }),
              dataCell("3,679", { width: 780, bold: true, color: GREEN }),
            ],
          }),
        ],
      }),

      p("", { spaceAfter: 80 }),
      p([
        { text: "Note: ", bold: true, color: GRAY, size: 18 },
        { text: "May, Jun, Jul 2024 have no COGS transactions (shown as \u201C-\u201D). First COGS appears in Aug 2024.", color: GRAY, size: 18 },
      ], { spaceAfter: 200 }),

      // Comparison Table
      p("Comparison: Old vs New Logic", { bold: true, size: 20, color: DK_BLUE, spaceAfter: 80 }),

      new Table({
        width: { size: 9360, type: WidthType.DXA },
        columnWidths: [3120, 3120, 3120],
        rows: [
