          }),
          new TableRow({
            children: [
              dataCell("Average COGS", { bold: true, align: AlignmentType.LEFT, fill: LT_GRAY }),
              dataCell("408.78", { bold: true, color: "C62828", size: 24 }),
              dataCell("306.59", { bold: true, color: GREEN, size: 24 }),
            ],
          }),
          new TableRow({
            children: [
              dataCell("Difference", { bold: true, align: AlignmentType.LEFT, fill: LT_GRAY }),
              new TableCell({
                borders,
                columnSpan: 2,
                shading: { fill: "FFF8E1", type: ShadingType.CLEAR },
                margins: { top: 60, bottom: 60, left: 100, right: 100 },
                children: [new Paragraph({
                  alignment: AlignmentType.CENTER,
