    paragraphStyles: [
      { id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true,
        run: { size: 32, bold: true, font: "Calibri", color: DK_BLUE },
        paragraph: { spacing: { before: 240, after: 120 }, outlineLevel: 0 } },
