const fs = require("fs");
const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, BorderStyle, WidthType, ShadingType,
  HeadingLevel, LevelFormat, PageBreak, PageNumber,
} = require("docx");

const DK_BLUE = "002776";
const RED = "FF0000";
const GREEN = "3C8A2E";
const AMBER = "ED8B00";
const BLUE = "00A1DE";
const GRAY = "575757";
const LT_GRAY = "F2F2F2";
const LINE_GRAY = "D0D0CE";

const border = { style: BorderStyle.SINGLE, size: 1, color: LINE_GRAY };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function p(text, opts = {}) {
  const runs = [];
  if (typeof text === "string") {
    runs.push(new TextRun({ text, font: "Calibri", size: opts.size || 22, bold: opts.bold, italic: opts.italic, color: opts.color || "313131" }));
  } else {
    text.forEach(t => {
      runs.push(new TextRun({ text: t.text, font: "Calibri", size: t.size || opts.size || 22, bold: t.bold, italic: t.italic, color: t.color || opts.color || "313131", break: t.break }));
    });
  }
  return new Paragraph({
    children: runs,
    spacing: { before: opts.spaceBefore || 0, after: opts.spaceAfter || 120 },
    alignment: opts.align || AlignmentType.LEFT,
    indent: opts.indent ? { left: opts.indent } : undefined,
    ...(opts.heading ? { heading: opts.heading } : {}),
    ...(opts.bullet ? { numbering: { reference: "bullets", level: 0 } } : {}),
    ...(opts.numbered ? { numbering: { reference: "numbers", level: 0 } } : {}),
  });
}

function headerCell(text, fill = DK_BLUE, width = 3120) {
  return new TableCell({
    borders,
    width: { size: width, type: WidthType.DXA },
    shading: { fill, type: ShadingType.CLEAR },
    margins: { top: 60, bottom: 60, left: 100, right: 100 },
    children: [new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text, font: "Calibri", size: 20, bold: true, color: "FFFFFF" })],
    })],
  });
}

function dataCell(text, opts = {}) {
  return new TableCell({
    borders,
    width: { size: opts.width || 3120, type: WidthType.DXA },
    shading: opts.fill ? { fill: opts.fill, type: ShadingType.CLEAR } : undefined,
    margins: { top: 60, bottom: 60, left: 100, right: 100 },
    children: [new Paragraph({
      alignment: opts.align || AlignmentType.CENTER,
      children: [new TextRun({ text, font: "Calibri", size: opts.size || 20, bold: opts.bold, color: opts.color || "313131" })],
    })],
  });
}

function separator() {
  return new Paragraph({
    spacing: { before: 120, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: RED, space: 4 } },
    children: [],
  });
}

function sectionHeader(text) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders: noBorders,
            width: { size: 9360, type: WidthType.DXA },
            shading: { fill: DK_BLUE, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 150, right: 150 },
            children: [new Paragraph({
              children: [new TextRun({ text, font: "Calibri", size: 22, bold: true, color: "FFFFFF" })],
            })],
          }),
        ],
      }),
    ],
  });
}

function calloutBox(titleText, bodyRuns, barColor, bgColor = LT_GRAY) {
