const fs = require("fs");
const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, BorderStyle, WidthType, ShadingType,
  LevelFormat, PageNumber,
} = require("docx");

const DK_BLUE = "002776";
const RED = "FF0000";
const GREEN = "3C8A2E";
const AMBER = "ED8B00";
const BLUE = "00A1DE";
const GRAY = "575757";
const LT_GRAY = "F2F2F2";
const LINE_GRAY = "D0D0CE";

const border = { style: BorderStyle.SINGLE, size: 1, color: LINE_GRAY };
const borders = { top: border, bottom: border, left: border, right: border };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

function p(text, opts = {}) {
  const runs = [];
  if (typeof text === "string") {
    runs.push(new TextRun({ text, font: "Calibri", size: opts.size || 22, bold: opts.bold, italic: opts.italic, color: opts.color || "313131" }));
  } else {
    text.forEach(t => {
      runs.push(new TextRun({ text: t.text, font: "Calibri", size: t.size || opts.size || 22, bold: t.bold, italic: t.italic, color: t.color || opts.color || "313131", break: t.break }));
    });
  }
  return new Paragraph({
    children: runs,
    spacing: { before: opts.spaceBefore || 0, after: opts.spaceAfter || 100 },
    alignment: opts.align || AlignmentType.LEFT,
    ...(opts.bullet ? { numbering: { reference: "bullets", level: 0 } } : {}),
  });
}

function hCell(text, fill = DK_BLUE, width = 3120) {
  return new TableCell({
    borders, width: { size: width, type: WidthType.DXA },
    shading: { fill, type: ShadingType.CLEAR },
    margins: { top: 50, bottom: 50, left: 80, right: 80 },
    children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text, font: "Calibri", size: 19, bold: true, color: "FFFFFF" })] })],
  });
}

function dCell(text, opts = {}) {
  return new TableCell({
    borders, width: { size: opts.width || 3120, type: WidthType.DXA },
    shading: opts.fill ? { fill: opts.fill, type: ShadingType.CLEAR } : undefined,
    margins: { top: 50, bottom: 50, left: 80, right: 80 },
    children: [new Paragraph({ alignment: opts.align || AlignmentType.CENTER, children: [new TextRun({ text, font: "Calibri", size: opts.size || 19, bold: opts.bold, color: opts.color || "313131" })] })],
  });
}

function separator() {
  return new Paragraph({ spacing: { before: 80, after: 80 }, border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: RED, space: 3 } }, children: [] });
}

function sectionBar(text) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA }, columnWidths: [9360],
    rows: [new TableRow({ children: [new TableCell({
      borders: noBorders, width: { size: 9360, type: WidthType.DXA },
      shading: { fill: DK_BLUE, type: ShadingType.CLEAR },
      margins: { top: 60, bottom: 60, left: 120, right: 120 },
      children: [new Paragraph({ children: [new TextRun({ text, font: "Calibri", size: 21, bold: true, color: "FFFFFF" })] })],
    })] })],
  });
}

const doc = new Document({
  styles: { default: { document: { run: { font: "Calibri", size: 22 } } } },
  numbering: { config: [
    { reference: "bullets", levels: [{ level: 0, format: LevelFormat.BULLET, text: "\u2022", alignment: AlignmentType.LEFT, style: { paragraph: { indent: { left: 720, hanging: 360 } } } }] },
  ] },
  sections: [{
    properties: {
      page: { size: { width: 12240, height: 15840 }, margin: { top: 1260, right: 1440, bottom: 1260, left: 1440 } },
    },
    headers: { default: new Header({ children: [
      new Paragraph({ border: { bottom: { style: BorderStyle.SINGLE, size: 6, color: RED, space: 3 } },
        children: [new TextRun({ text: "CMG Unified Data Platform  |  Stock Aging  |  Average COGS Calculation", font: "Calibri", size: 15, color: GRAY })] }),
    ] }) },
    footers: { default: new Footer({ children: [
      new Paragraph({ border: { top: { style: BorderStyle.SINGLE, size: 4, color: LINE_GRAY, space: 3 } },
        children: [
          new TextRun({ text: "Confidential  |  Deloitte Consulting  |  Page ", font: "Calibri", size: 15, color: GRAY }),
          new TextRun({ children: [PageNumber.CURRENT], font: "Calibri", size: 15, color: GRAY }),
        ] }),
    ] }) },
    children: [
      // Subject
      p([
        { text: "Subject: ", bold: true, color: GRAY },
        { text: "Stock Aging \u2014 Average COGS Calculation: Current vs Proposed Approach", bold: true, color: DK_BLUE },
      ], { spaceAfter: 160, size: 23 }),

      separator(),

      p("Dear All,", { spaceAfter: 120 }),
      p("Below is a comparison of the current and proposed approach for calculating Average COGS in the Stock Aging report, with a real data example.", { spaceAfter: 160 }),

      // ===== CURRENT =====
      sectionBar("Current Approach"),
      p("", { spaceAfter: 60 }),
      p([
        { text: "Looks at the " },
        { text: "last 12 months", bold: true },
        { text: " from the report date. Denominator (N) = " },
        { text: "span", bold: true },
        { text: " from first COGS transaction in the window to current month. Does not check history before the window." },
      ], { spaceAfter: 120 }),

      // ===== PROPOSED =====
      sectionBar("Proposed Approach"),
      p("", { spaceAfter: 60 }),
      p([
        { text: "Adds one step: checks if the SKU has " },
        { text: "any data before the 12-month window", bold: true },
        { text: " (back to 2018)." },
      ], { spaceAfter: 60 }),
      p([
        { text: "Has history \u2192 ", bold: true },
        { text: "N = 12 immediately", bold: true, color: GREEN },
        { text: "  (existing/seasonal SKU)" },
      ], { bullet: true, spaceAfter: 40 }),
      p([
        { text: "No history \u2192 ", bold: true },
        { text: "N = count of months with actual values", bold: true, color: AMBER },
        { text: "  (new SKU)" },
      ], { bullet: true, spaceAfter: 160 }),

      // ===== REAL DATA =====
      separator(),
      sectionBar("Real Data: Article 11711000001 (Crocs) \u2014 Report Month: Apr 2025"),
      p("", { spaceAfter: 60 }),
      p([
        { text: "12-month window: May 2024 \u2013 Apr 2025. ", size: 20 },
        { text: "This SKU has COGS data in Feb 2024 (before the window).", size: 20, bold: true },
      ], { spaceAfter: 80 }),

      // Monthly table
      new Table({
        width: { size: 9360, type: WidthType.DXA },
        columnWidths: [1560, 780, 780, 780, 780, 780, 780, 780, 780, 780, 780],
        rows: [
          new TableRow({ children: [
            hCell("Month", DK_BLUE, 1560),
            hCell("Aug", DK_BLUE, 780), hCell("Sep", DK_BLUE, 780), hCell("Oct", DK_BLUE, 780),
            hCell("Nov", DK_BLUE, 780), hCell("Dec", DK_BLUE, 780), hCell("Jan", DK_BLUE, 780),
            hCell("Feb", DK_BLUE, 780), hCell("Mar", DK_BLUE, 780), hCell("Apr", DK_BLUE, 780),
            hCell("Total", GREEN, 780),
          ] }),
          new TableRow({ children: [
            dCell("COGS", { bold: true, align: AlignmentType.LEFT, width: 1560, fill: LT_GRAY }),
            dCell("749", { width: 780 }), dCell("204", { width: 780 }), dCell("477", { width: 780 }),
            dCell("1,226", { width: 780 }), dCell("545", { width: 780 }), dCell("273", { width: 780 }),
            dCell("-", { width: 780, color: LINE_GRAY }), dCell("136", { width: 780 }), dCell("68", { width: 780 }),
            dCell("3,679", { width: 780, bold: true, color: GREEN }),
          ] }),
        ],
      }),
      p([
        { text: "May\u2013Jul 2024 and Feb 2025 have no COGS (omitted). First value in window: Aug 2024.", color: GRAY, size: 17 },
      ], { spaceBefore: 40, spaceAfter: 120 }),

      // Comparison table
      new Table({
        width: { size: 9360, type: WidthType.DXA },
        columnWidths: [2800, 3280, 3280],
        rows: [
          new TableRow({ children: [
            hCell("", DK_BLUE, 2800),
            hCell("Current", "C62828", 3280),
            hCell("Proposed", GREEN, 3280),
          ] }),
          new TableRow({ children: [
            dCell("Historical Check", { bold: true, align: AlignmentType.LEFT, width: 2800, fill: LT_GRAY }),
            dCell("Not performed", { width: 3280 }),
            dCell("Finds Feb 2024 data", { width: 3280, color: GREEN }),
          ] }),
          new TableRow({ children: [
            dCell("Denominator (N)", { bold: true, align: AlignmentType.LEFT, width: 2800, fill: LT_GRAY }),
            dCell("9 (span)", { width: 3280, bold: true, color: "C62828" }),
            dCell("12 (has history)", { width: 3280, bold: true, color: GREEN }),
